import React from "react";

const Values = {
    title: 'Möta motståndet och våga jobba med frågan',
    video: {
        title: 'Vad skulle man kunna göra',
        link: 'https://www.youtube-nocookie.com/embed/XbyBp5oBFbA'
    },
    text: 'När en kvinna samlar kraft och berättar om sin situation är det viktigt att bemöta det, att kvinnan inte möts av motstånd. Gulderen pratar om församlingarnas roll att kunna möta dessa typer av frågor. Hon ser att det är viktigt att prata om relationer i ett tidigt stadie. Relationer kan vara svåra, därför kan vara viktigt att ha ett samtal med någon som kan vägleda båda personerna i relationen.',
}
export default Values;
